  ('bookkeeper-moex-00772', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '營利事業修繕固定資產，耐用年限 5 年，依現行營利事業所得稅查核準則，該修繕支出金額不超過新臺 幣多少元者，得列為當年度費用？', '["8萬元", "15萬元", "30萬元", "50萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00773', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '非適用勞動基準法之營利事業，定有職工退休辦法但未設置獨立之職工退休基金，其年度已支付的薪資 總額2,000萬元。按現行營利事業所得稅查核準則，該年度最多得提列以費用項目列支的職工退休金準備 是多少？', '["40萬元", "80萬元", "120萬元", "300萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00774', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依加值型及非加值型營業稅法，由主管稽徵機關查定銷售額及計算稅額之有娛樂節目之餐飲店營業人， 其營業稅多久由主管稽徵機關填發繳款書通知繳納一次？', '["每一個月", "每二個月", "每三個月", "每六個月"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00775', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依一般稅額規定計稅之營業人，進項稅額憑證未於當期申報者，其申報扣抵期間，最長以多久為限？', '["3年", "5年", "7年", "10年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00776', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '農產品批發市場之承銷人向農產品批發市場承購農產品，在同一市場或運往其他批發市場交易之銷售 額，營業稅率是多少？', '["免稅", "0.1%", "1%", "5%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00777', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '若營業人購入物品當作中秋節交際應酬使用，並以進貨科目列帳，且該物品已支付進項稅額，營業人以 該貨物餽贈客戶而無償移轉時，下列何者正確？', '["免視為銷售貨物，並免開立統一發票", "視為銷售貨物，但免開立統一發票", "免視為銷售貨物，需開立統一發票", "視為銷售貨物，需開立統一發票"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00778', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '租賃公司出租之自用汽車，因承租人遲延返還而加收之違約金，依現行加值型及非加值型營業稅法規定：', '["屬銷售額，應開立統一發票", "屬銷售額，免開立統一發票", "不屬銷售額，應開立統一發票", "不屬銷售額，免開立統一發票"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00779', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '查定計算營業稅額之小規模營業人，購買營業上使用之貨物，取得載有營業稅額之憑證，並依規定申報 且其查定稅額達起徵點者，其進項稅額得扣減多少？', '["不得扣減", "10%", "50%", "100%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00780', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '營業人漏開統一發票或於統一發票上短開銷售額，於法定申報期限前經查獲者，應就其所漏稅額繳納稅 款，並應按該稅額處幾倍以下罰鍰？另營業人之前項情形，一年內經查獲達幾次者，停止其營業？', '["三倍；三次", "三倍；五次", "五倍；三次", "五倍；五次"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00781', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '外國公司在中華民國境內無固定營業場所而有銷售勞務者，應由勞務買受人於給付報酬之次期開始多久 內，就給付額依適用稅率計算營業稅額繳納之？', '["15日", "20日", "25日", "30日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
